@startuml
skinparam classAttributeIconSize 0
skinparam packageStyle rectangle

package "javafx" {
  abstract class Application {
    +start(stage : Stage)
  }
}

class Main {
  +main(args : String[])
}

class App {
  +main(args : String[])
  +^start(stage : Stage)
}

class ConnexionView
class HomeView
class FolderView

class ConnexionController {
  -username : TextField
  -password : PasswordField
  +login()
}

class HomeController {
  +loadFolder()
  +logout()
}

class FolderController <<ConcretSubject>> {
  +addAntecedent()
  +addVisit()
  +restoreFolder()
  +saveFolder()
}

package "java" {
  package "util" {
    class Observable <<Subject>> {
      +addObserver(Observer o)
      +deleteObserver(Observer o)
      +notifyObservers()
      +notifyObservers(arg: Object)
      +setChanged()
    }

    interface Observer {
      +update(obs : java.util.Observable, arg: Object)
    }

    Observable "1" --> "0..n" Observer
  }
}

interface Authenticable {
  +login(user: String, pass: String) : boolean
}

class Session <<Director>> {
  +login(user: String, pass: String) : boolean
  +downloadFolder() : boolean
  +resetFolder() : boolean
  +getCurrentFolder() : Folder
  +getVisits() : Set<Visit>
  +getModifications() : Set<Antecedent>
  +getAntecedents() : Set<Antecedent>
  +getDoctor() : Doctor
  +<<construct>> createNewVisit(treatment: String, diagnostic: String, ...)
}

class DataSource {
  +^findbyId(id : String) : Folder
  +^findbyUsernameAndPassword(username : String, password: String) : User
  +^update(f : Folder) : boolean
  -archiveModification(f : Folder) : boolean
  -encryptPasswordToSHA1(pass: String) : String
}

interface Editable {
  +update(f : Folder)
}

interface Searchable {
  +findbyId(id : String) : Folder
  +findbyUsernameAndPassword(username : String, password: String) : User
}

class Folder <<Prototype>> <<ConcretObserver>> {
  +addVisit(v: Visit)
  +addAntecedent(a: Antecedent)
  +getVisits() : List<Visit>
  +getAntecedents() : List<Antecedent>
  +<<clone>> duplicate() : Folder
  +update()
}

class User {
  -username : String
  -password : String
}

class VisitBuilder <<ConcreteBuilder>> {
  +<<buildPart()>> setTreatment(designation : String)
  +<<buildPart()>> setTreatment(designation : String)
  +<<result()>> build() : Visit
}

class Visit <<Product>> {
  -date : Date
  -summary : String
  -notes : String
}

class Antecedent {
  -beginning : Date
  -end : Date
}

class Treatment <<ProductPart>> {
  -designation : String
}

class Diagnostic <<ProductPart>> {
  -designation : String
}

class Doctor {
  -lastname : String
  -firstname : String
  -permit : String
  -speciality : String
}

class Establishment {
  -identification : String
  -designation : String
}

class Patient {
  -lastname : String
  -firstname : String
  -dateOfBirth : Date
  -birthCity : String
  -insuranceNumber : String
  -father : String
  -mother : String
}

enum Gender {
  MALE
  FEMALE
  OTHER
}

class Contact {
  -address : String
  -phone : String
  -email : String
}

Application <|-- App

Main ..> App
App ..> ConnexionController
ConnexionView -- ConnexionController
HomeView -- HomeController
FolderView -- FolderController
HomeController ..> FolderController

Session ..|> Authenticable

ConnexionController --> Session
HomeController --> Session
FolderController --> Session
App ..> Session

Session --> DataSource

DataSource ..|> Searchable
DataSource ..|> Editable

FolderController ..> Observer
FolderController --> Observable

Session "0..1\noriginalFolder" --> Folder
Session "0..1\ncurrentFolder" --> Folder

Session "0..1\nuser" --> User

Session --> VisitBuilder
VisitBuilder ..> Visit

Folder "0..1\nnewVisit" o-- Visit : visits
Folder o-- "*" Antecedent : antecedents

Visit "0..1\ntreatment" --> Treatment
Visit "0..1\ndiagnostic" --> Diagnostic

Visit "1\ndoctor prescriber" --> Doctor
User "1\ndoctor" --> Doctor

Doctor "1\nestablishment" --> Establishment

Folder "1\nowner" --> Patient
Patient "1\ngender" --> Gender
Patient "1\ncontact" --> Contact
@enduml
